/// <reference lib="webworker" />

import init, {
  init as wasmInit,
  frame_ptr,
  frame_capacity,
  decode_frame,
  set_binarizer_strategy,
  last_binarizer_used,
} from '../../pkg/qr_reader_wasm.js';

import type {
  WorkerInbound,
  WorkerOutbound,
  ReadyOutbound,
  DecodedOutbound,
  FrameDoneOutbound,
  ErrorOutbound,
} from '../decoder/protocol';
import type { DecoderStats } from '../types';

declare const self: DedicatedWorkerGlobalScope;

interface WasmModule {
  memory: WebAssembly.Memory;
}

let wasmModule: WasmModule | null = null;
let lastBuffer: ArrayBufferLike | null = null;
let lastView: Uint8ClampedArray | null = null;
let activeWidth = 0;
let activeHeight = 0;

const stats: DecoderStats = {
  framesProcessed: 0,
  framesDecoded: 0,
  lastBinarizerUsed: '',
  lastDecodeMs: 0,
};

function post(msg: WorkerOutbound, transfer?: Transferable[]): void {
  if (transfer && transfer.length > 0) {
    self.postMessage(msg, transfer);
  } else {
    self.postMessage(msg);
  }
}

function ensureView(): Uint8ClampedArray {
  if (!wasmModule) {
    throw new Error('wasm not initialized');
  }
  const buf = wasmModule.memory.buffer;
  if (buf !== lastBuffer || lastView === null) {
    const ptr = frame_ptr();
    const cap = frame_capacity();
    lastView = new Uint8ClampedArray(buf, ptr, cap);
    lastBuffer = buf;
  }
  return lastView;
}

async function onInit(width: number, height: number): Promise<void> {
  if (!wasmModule) {
    const module = await init();
    wasmModule = { memory: module.memory };
  }
  wasmInit(width, height);
  activeWidth = width;
  activeHeight = height;
  ensureView();
  const ready: ReadyOutbound = { type: 'ready', width, height };
  post(ready);
}

function onFrame(rgba: Uint8ClampedArray, width: number, height: number, frameId: number): void {
  if (!wasmModule) {
    return;
  }
  if (width !== activeWidth || height !== activeHeight) {
    const err: ErrorOutbound = {
      type: 'error',
      code: 'frame_size_mismatch',
      message: `expected ${activeWidth}x${activeHeight}, got ${width}x${height}`,
    };
    post(err);
    return;
  }

  const view = ensureView();
  const n = width * height * 4;
  view.set(rgba.subarray(0, n));

  const t0 = performance.now();
  const payload = decode_frame();
  const t1 = performance.now();

  stats.framesProcessed += 1;
  stats.lastDecodeMs = t1 - t0;
  stats.lastBinarizerUsed = last_binarizer_used() || '';

  if (payload && payload.length > 0) {
    stats.framesDecoded += 1;
    const out: DecodedOutbound = {
      type: 'decoded',
      payload,
      frameId,
      stats: { ...stats },
      rgba,
    };
    post(out, [rgba.buffer]);
  } else {
    const out: FrameDoneOutbound = {
      type: 'frame_done',
      frameId,
      stats: { ...stats },
      rgba,
    };
    post(out, [rgba.buffer]);
  }
}

self.onmessage = (ev: MessageEvent<WorkerInbound>) => {
  const msg = ev.data;
  try {
    switch (msg.type) {
      case 'init':
        onInit(msg.width, msg.height).catch((e) => {
          const err: ErrorOutbound = {
            type: 'error',
            code: 'wasm_init_failed',
            message: e instanceof Error ? e.message : String(e),
          };
          post(err);
        });
        break;
      case 'frame':
        onFrame(msg.rgba, msg.width, msg.height, msg.frameId);
        break;
      case 'set_strategy':
        set_binarizer_strategy(msg.strategy === 'auto' ? '' : msg.strategy);
        break;
      case 'dispose':
        wasmModule = null;
        lastBuffer = null;
        lastView = null;
        break;
    }
  } catch (e) {
    const err: ErrorOutbound = {
      type: 'error',
      code: 'unknown',
      message: e instanceof Error ? e.message : String(e),
    };
    post(err);
  }
};
